print(f"3. Blob: {blob['sha']}")

# 4. Create tree
tree = api("git/trees", {
    "base_tree": base_tree,
    "tree": [{"path": "middleware.ts", "mode": "100644", "type": "blob", "sha": blob["sha"]}]
})
print(f"4. Tree: {tree['sha']}")

# 5. Create commit
